#include<stdio.h>


int main()
{
	int n,p,k,s;
	scanf("%d %d %d",&n,&p,&k);
	if ((p-k)<=1)
	printf("");
	else
	printf("<<");
	////////
	for (int i=0;i<=k;i++)
	{
	if (i!=k)
	{
	if (p-k+i>0)
	printf(" %d",p-k+i);
	else
	printf("");
	}
	else
	printf(" (%d)",p);
	}
	////////////
	for (int i=0;i<=k;i++)
	{
	s=p+1+i;
	if (s<=n)
	{
	if (i!=k)
	printf(" %d",s);
	}
	else
	printf("");
	}
	if (s<=n)
	printf(" >>");
	else
	printf("");
	return 0;
}

