use std::io;

fn main() {
    let mut result = String::new();

    let mut buf = String::new();
    io::stdin().read_line(&mut buf).unwrap();
    let mut buf = buf
        .trim()
        .split_whitespace()
        .map(|num| num.parse::<usize>().unwrap())
        .take(3);
    let (n, p, k) = (
        buf.next().unwrap(),
        buf.next().unwrap(),
        buf.next().unwrap(),
    );

    // Add begining (before 'p')
    if (1..=(k + 1)).contains(&p) {
        for i in 1..p {
            result.push_str(&format!("{} ", i));
        }
    } else {
        result.push_str("<< ");
        for i in (p - k)..p {
            result.push_str(&format!("{} ", i));
        }
    }

    result.push_str(&format!("({})", p));

    // Add ending (after 'p')
    if ((n - k)..=n).contains(&p) {
        for i in (p + 1)..=n {
            result.push_str(&format!(" {}", i));
        }
    } else {
        for i in (p + 1)..=(p + k) {
            result.push_str(&format!(" {}", i));
        }
        result.push_str(" >>");
    }

    println!("{}", result);
}
